import React, { useState } from "react";
import "../styles/GeneralChat.css";

const therapistReplies = [
  {
    keywords: ["hello", "hi", "hey"],
    reply: "Hi 🌱 I’m here with you. How are you feeling today?"
  },
  {
    keywords: ["tired", "exhausted", "draining", "burnt"],
    reply:
      "Feeling exhausted can be really heavy — emotionally and physically. Do you want to talk about what’s been draining you?"
  },
  {
    keywords: ["yes", "i want to tell", "sure"],
    reply:
      "Take your time 💜 I’m listening. What’s been weighing on your mind lately?"
  },
  {
    keywords: ["song", "music"],
    reply:
      "When you’re exhausted, gentle music can really help 🌙\n\nTry:\n• *Fix You* – Coldplay\n• *Someone You Loved* – Lewis Capaldi\n• *Let Her Go* – Passenger\n• *Weightless* – Marconi Union\n\nDo you usually listen to music when you feel low?"
  },
  {
    keywords: ["sad", "cry", "lonely", "alone"],
    reply:
      "I’m really sorry you’re feeling this way 💙 You don’t have to go through it alone. What usually makes these feelings stronger?"
  }
];

const defaultReply =
  "I hear you. That sounds difficult. Can you tell me a little more about what you’re experiencing? 💜";

function getTherapistReply(message) {
  const lowerMsg = message.toLowerCase();

  for (let item of therapistReplies) {
    if (item.keywords.some(word => lowerMsg.includes(word))) {
      return item.reply;
    }
  }
  return defaultReply;
}

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text:
        "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?"
    }
  ]);
  const [input, setInput] = useState("");

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: getTherapistReply(input)
    };

    setMessages(prev => [...prev, userMessage, botMessage]);
    setInput("");
  };

  return (
    <div className="general-chat-container">
      <h2 className="chat-title">General Chat</h2>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={msg.sender === "user" ? "user-msg" : "bot-msg"}
          >
            {msg.text}
          </div>
        ))}
      </div>

      <div className="chat-input-area">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={e => setInput(e.target.value)}
          onKeyDown={e => e.key === "Enter" && handleSend()}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
